# All blocks are "outside" with 4-connectivity. The 5s don't form closed boundaries
# that trap blocks inside.

# Let me try 8-connectivity for the flood fill (diagonal connections too)
# Actually, the 5-path IS open, not necessarily closed.

# Let me reconsider. Maybe the 5s are a PATH that connects from certain blocks to others.
# The 5s trace a connected path. Let me see which blocks the 5-path touches.

# The 5s form a connected component. Let me find it and see which blocks it's adjacent to.

from collections import deque

for idx in range(3):
    inp = np.array(train_samples[idx]['input'])
    out = np.array(train_samples[idx]['output'])
    H, W = inp.shape

    # Find connected components of 5s (8-connected)
    five_positions = set(zip(*np.where(inp == 5)))

    components_5 = []
    visited_5 = set()
    for pos in five_positions:
        if pos not in visited_5:
            comp = set()
            queue = deque([pos])
            visited_5.add(pos)
            while queue:
                r, c = queue.popleft()
                comp.add((r,c))
                for dr in [-1,0,1]:
                    for dc in [-1,0,1]:
                        if dr == 0 and dc == 0: continue
                        nr, nc = r+dr, c+dc
                        if (nr,nc) in five_positions and (nr,nc) not in visited_5:
                            visited_5.add((nr,nc))
                            queue.append((nr,nc))
            components_5.append(comp)

    print(f"\nEx{idx}: {len(components_5)} connected 5-component(s)")

    # For each 5 component, which blocks does it connect?
    blocks = []
    for r in range(H-2):
        for c in range(W-2):
            sub = inp[r:r+3, c:c+3]
            border_vals = [sub[0,0],sub[0,1],sub[0,2],sub[1,0],sub[1,2],sub[2,0],sub[2,1],sub[2,2]]
            center = sub[1,1]
            if len(set(border_vals)) == 1 and border_vals[0] != 0 and border_vals[0] != 5 and center != border_vals[0] and center != 0 and center != 5:
                out_sub = out[r:r+3, c:c+3]
                kept = not np.all(out_sub == 0)
                block_cells = set()
                for br in range(r, r+3):
                    for bc in range(c, c+3):
                        block_cells.add((br, bc))

                # Find which 5-component is adjacent
                adj_comp = None
                for ci, comp in enumerate(components_5):
                    for cr, cc in comp:
                        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                            if (cr+dr, cc+dc) in block_cells:
                                adj_comp = ci
                                break
                        if adj_comp is not None:
                            break

                blocks.append({'pos': (r,c), 'border': int(border_vals[0]), 'center': int(center), 'kept': kept, 'adj_comp': adj_comp})

    for b in blocks:
        print(f"  Block ({b['pos']}): border={b['border']}, center={b['center']}, {'KEPT' if b['kept'] else 'REMOVED'}, adj_5_comp={b['adj_comp']}")

