# Let me use 8-connectivity instead for the 5-path graph.

for idx in range(3):
    inp = np.array(train_samples[idx]['input'])
    H, W = inp.shape

    five_set = set(zip(*np.where(inp == 5)))

    # Build adjacency graph of 5-cells (8-connected)
    adj = {pos: [] for pos in five_set}
    for r, c in five_set:
        for dr in [-1,0,1]:
            for dc in [-1,0,1]:
                if dr == 0 and dc == 0: continue
                if (r+dr, c+dc) in five_set:
                    adj[(r,c)].append((r+dr, c+dc))

    degrees = {pos: len(neighbors) for pos, neighbors in adj.items()}
    endpoints = [pos for pos, d in degrees.items() if d <= 1]
    branches = [pos for pos, d in degrees.items() if d >= 3]

    blocks = find_blocks(train_samples[idx]['input'])
    out = np.array(train_samples[idx]['output'])
    for b in blocks:
        r, c = b['pos']
        b['kept'] = out[r][c] != 0

    print(f"\nTraining {idx}:")
    print(f"  8-conn endpoints: {[(int(r),int(c)) for r,c in endpoints]}")
    print(f"  8-conn branches: {[(int(r),int(c)) for r,c in branches]}")

    for ep in endpoints:
        r, c = ep
        for b in blocks:
            for cell in b['cells']:
                # Check 8-adjacency
                if max(abs(cell[0]-r), abs(cell[1]-c)) <= 1 and (cell[0]-r, cell[1]-c) != (0,0):
                    status = 'K' if b['kept'] else 'R'
                    print(f"  Endpoint ({int(r)},{int(c)}) 8-adj to block {b['pos']} {status}")
                    break

