        kept = {}

        for _ in range(len(blocks)+1):
            if not active: break
            # Find targets
            targets = set()
            for b in active.values():
                for t in active.values():
                    if b['center'] == t['border']:
                        targets.add(t['pos']); break
            heads = [b for b in active.values() if b['pos'] not in targets]
            if not heads: break

            to_remove = set()
            for head in heads:
                target = None
                for t in active.values():
                    if head['center'] == t['border']:
                        target = t; break
                if target:
                    kept[head['pos']] = target['center']
                    to_remove.add(target['pos'])
                to_remove.add(head['pos'])
            for pos in to_remove:
                active.pop(pos, None)
        return build_output(kept)

    # Check if there's a convergence (Y-shape)
    from collections import Counter
    target_counts = Counter()
    for b in blocks:
        if b['center'] in border_map:
            target_counts[border_map[b['center']]['pos']] += 1
    has_convergence = any(v > 1 for v in target_counts.values())

    r1 = method_longest_chain()
    if has_convergence:
        r2 = method_parallel()
        if r1 != r2:
            return [r1, r2]
    return r1

