                blocks.append({'pos':p,'border':bc,'center':ct,'cells':[(0,c+i) for i in range(3)]+[(1,c+i) for i in range(3)]})
                found_centers.add(p)

    if W >= 2:
        c = W-2
        for r in range(H-2):
            p = (r+1, c+1)
            if p in found_centers: continue
            col1, col2 = [grid[r+i][c] for i in range(3)], [grid[r+i][c+1] for i in range(3)]
            bc, ct = col1[0], col2[1]
            if bc!=0 and bc!=5 and ct!=0 and ct!=5 and ct!=bc and all(v==bc for v in [col1[0],col1[1],col1[2],col2[0],col2[2]]):
                blocks.append({'pos':p,'border':bc,'center':ct,'cells':[(r+i,c) for i in range(3)]+[(r+i,c+1) for i in range(3)]})
                found_centers.add(p)

    if W >= 2:
        c = 0
        for r in range(H-2):
            p = (r+1, c)
            if p in found_centers: continue
            col1, col2 = [grid[r+i][c] for i in range(3)], [grid[r+i][c+1] for i in range(3)]
            bc, ct = col2[0], col1[1]
            if bc!=0 and bc!=5 and ct!=0 and ct!=5 and ct!=bc and all(v==bc for v in [col2[0],col2[1],col2[2],col1[0],col1[2]]):
                blocks.append({'pos':p,'border':bc,'center':ct,'cells':[(r+i,c) for i in range(3)]+[(r+i,c+1) for i in range(3)]})
                found_centers.add(p)

    border_map = {b['border']: b for b in blocks}
    all_centers = {b['center'] for b in blocks}

    def build_output(kept_dict):
        output = [[0]*W for _ in range(H)]
        for r in range(H):
            for c in range(W):
                if grid[r][c] == 5:
                    output[r][c] = 5
